(function(){
    var dplayerContainer = document.getElementById('dplayer');
    var videoUrl = dplayerContainer.dataset.videoUrl;
    var dpOptions = {
        container: dplayerContainer,
        autoplay: true,
        theme: '#ff2626',
        loop: false,
        lang: 'zh-cn',
        screenshot: true,
        hotkey: false,
        video: {
            pic: '',
            quality: [{url: videoUrl, type: 'auto', name: '自动'}],
            defaultQuality: 0,
        },
        preload: 'metadata',
        volume: 1.0
    };
    var dplayerInstance = new DPlayer(dpOptions);
    dplayerContainer.style.display = 'block';
    dplayerContainer.dp = dplayerInstance;
    dplayerContainer.dp.volume(1.0, false, true);
    var speedList = [10,5,3,2,1.5,1.25,1,0.75,0.5,0.25];
    var speedPanel = dplayerContainer.querySelector('.dplayer-setting-speed-panel');
    var speedLabel = dplayerContainer.querySelector('.dplayer-setting-speed .dplayer-label');
    if (speedPanel && speedLabel) {
        speedLabel.textContent = '倍速';
        speedPanel.innerHTML = '';
        speedList.forEach(function(speed){
            var item = document.createElement('div');
            item.className = 'dplayer-setting-speed-item';
            item.setAttribute('data-speed', speed);
            var label = document.createElement('span');
            label.className = 'dplayer-label';
            label.textContent = (speed === 1) ? '正常' : (Number.isInteger(speed) ? speed.toFixed(1) : speed) + 'x';
            item.appendChild(label);
            item.onclick = function(){
                dplayerInstance.speed(speed);
                speedPanel.querySelectorAll('.dplayer-setting-speed-item').forEach(function(i){i.classList.remove('dplayer-setting-speed-item-active');});
                item.classList.add('dplayer-setting-speed-item-active');
            };
            if (dplayerInstance.video.playbackRate === speed) {
                item.classList.add('dplayer-setting-speed-item-active');
            }
            speedPanel.appendChild(item);
        });
    }
    function enableGlobalKeys(dp) {
        if (window.__AE_GLOBAL_KEYS_BOUND__) return;
        window.__AE_GLOBAL_KEYS_BOUND__ = true;
        var HOLD_THRESHOLD_MS = 240, FAST_RATE = 2.0, NORMAL_RATE = 1.0;
        var rightHoldTimer = null, rightIsHolding = false, rightDidHold = false;
        function setRate(rate) { if (!dp || !dp.video) return; dp.video.playbackRate = rate; }
        function resetRightHold() {
            if (rightHoldTimer) { clearTimeout(rightHoldTimer); rightHoldTimer = null; }
            if (rightIsHolding) {
                rightIsHolding = false;
                setRate(NORMAL_RATE);
                dp.notice('倍速: ' + NORMAL_RATE + 'x', 3000);
            }
        }
        window.addEventListener('blur', resetRightHold);
        document.addEventListener('visibilitychange', function(){ if (document.hidden) resetRightHold(); });
        window.addEventListener('keydown', function(e){
            if (!dp || !dp.video) return;
            if (e.ctrlKey || e.metaKey || e.altKey) return;
            var v = dp.video;
            if (e.key === ' ') { e.preventDefault(); dp.toggle(); dp.notice(v.paused ? "已暂停" : "播放中", 3000); }
            if (e.key === 'ArrowLeft') { e.preventDefault(); v.currentTime = Math.max(0, v.currentTime - 5); dp.notice('倒退 5 秒', 3000);}
            if (e.key === 'ArrowRight') {
                e.preventDefault();
                if (e.repeat) return;
                rightDidHold = false;
                if (!rightHoldTimer && !rightIsHolding) {
                    rightHoldTimer = setTimeout(function(){
                        rightHoldTimer = null;
                        rightIsHolding = true;
                        rightDidHold = true;
                        setRate(FAST_RATE);
                        dp.notice('▶▶▶ 2x 倍速播放中', 99999999999999);
                    }, HOLD_THRESHOLD_MS);
                }
            }
            if (e.key === 'ArrowUp') { e.preventDefault(); var step = 0.05; var next = Math.min(1, dp.volume() + step); dp.volume(next, true, true); dp.notice('音量: ' + Math.round(next * 100) + '%', 3000);}
            if (e.key === 'ArrowDown') { e.preventDefault(); var step = 0.05; var next = Math.max(0, dp.volume() - step); dp.volume(next, true, true); dp.notice('音量: ' + Math.round(next * 100) + '%', 3000);}
        }, { capture: true, passive: false });
        window.addEventListener('keyup', function(e){
            if (!dp || !dp.video) return;
            if (e.key === 'ArrowRight') {
                e.preventDefault();
                if (rightHoldTimer) { clearTimeout(rightHoldTimer); rightHoldTimer = null; }
                if (rightDidHold || rightIsHolding) { rightDidHold = false; resetRightHold(); return; }
                var v = dp.video;
                v.currentTime = Math.min(v.duration || Infinity, v.currentTime + 5);
                dp.notice('前进 5 秒', 3000);
            }
        }, { capture: true, passive: false });
    }
    enableGlobalKeys(dplayerInstance);

    function disableDPlayerNoticeQueue(dp, containerEl) {
        if (!dp || dp.__noticeQueueDisabled) return;
        dp.__noticeQueueDisabled = true;
        var root = containerEl || dp.container || dplayerContainer;
        function clearNotices() {
            var list = root && root.querySelector ? root.querySelector('.dplayer-notice-list') : null;
            if (list) list.innerHTML = '';
        }
        if (typeof dp.notice === 'function') {
            var originalNotice = dp.notice.bind(dp);
            dp.notice = function () {
                clearNotices();
                var msg = arguments[0];
                if (typeof msg === 'string') {
                    var match = msg.match(/(快进|倒退)\s+(\d+)\s+秒/);
                    if (match) {
                        var formattedTime = formatSeconds(parseInt(match[2], 10));
                        var newMsg = match[1] + ' ' + formattedTime;
                        return originalNotice.apply(dp, [newMsg].concat(Array.prototype.slice.call(arguments,1)));
                    }
                }
                return originalNotice.apply(dp, arguments);
            };
        }
    }
    function formatSeconds(seconds) {
        var hours = Math.floor(seconds / 3600);
        var minutes = Math.floor((seconds % 3600) / 60);
        var secs = seconds % 60;
        if (hours > 0) { return hours + ' 小时 ' + minutes + ' 分钟 ' + secs + ' 秒'; }
        else if (minutes > 0) { return minutes + ' 分钟 ' + secs + ' 秒'; }
        else { return secs + ' 秒'; }
    }
    disableDPlayerNoticeQueue(dplayerInstance, dplayerContainer);

    const video = dplayerContainer.dp.video;
    video.addEventListener('loadedmetadata', function() {
        const width = video.videoWidth;
        const height = video.videoHeight;
        let newName = (width * height === 0) ? '自动' : (width + 'x' + height);
        let evalWidth = width;
        let evalHeight = height;
        if (width < height) {
            evalWidth = height;
            evalHeight = width;
        }
        if (evalWidth > 14000 && evalHeight > 6000) {
            newName = "16K 超高清";
        } else if (evalWidth > 7000 && evalHeight > 4000) {
            newName = "8K 超高清";
        } else if (evalWidth > 4000 && evalHeight > 3000) {
            newName = "4K 超高清";
        } else if (evalWidth > 2000 && evalHeight > 1500) {
            newName = "2K 超清";
        } else if (evalWidth > 1000 && evalHeight > 750) {
            newName = "1080P 高清";
        } else if (evalWidth > 500 && evalHeight > 375) {
            newName = "720P 准高清";
        } else if (evalWidth > 500 && evalHeight > 500) {
            newName = "480P 标清";
        } else if (evalWidth > 300 && evalHeight > 300) {
            newName = "360P 流畅";
        }
        const qualityBtn = dplayerContainer.querySelector('.dplayer-quality-icon');
        const qualityItem = dplayerContainer.querySelector('.dplayer-quality-item');
        if (qualityBtn) {
            qualityBtn.textContent = newName;
        }
        if (qualityItem) {
            qualityItem.textContent = newName;
        }
    });

    setTimeout(function(){
        const dplayerLabel = dplayerContainer.querySelector('.dplayer-setting-loop .dplayer-label');
        if (dplayerLabel) dplayerLabel.textContent = '循环播放';
        const dplayerLabelFps = dplayerContainer.querySelector('.dplayer-info-panel-item-fps');
        if (dplayerLabelFps) dplayerLabelFps.style.display = 'none';
        const dplayerFullInIcon = dplayerContainer.querySelector('.dplayer-full-in-icon');
        if (dplayerFullInIcon) dplayerFullInIcon.style.display = 'none';
        const aboutAuthorItem = dplayerContainer.querySelector('.dplayer-menu-item a[href="https://diygod.me"]');
        if (aboutAuthorItem) aboutAuthorItem.closest('.dplayer-menu-item').remove();
        const aboutPlayerItem = dplayerContainer.querySelector('.dplayer-menu-item a[href="https://github.com/MoePlayer/DPlayer"]');
        if (aboutPlayerItem) aboutPlayerItem.textContent = 'Powered by DPalyer';
    }, 1200);
})();